parameters.jsCode:
const raw = $input.first().json.output || '';
// Strip markdown fences if present
const clean = raw.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
let parsed;
try { parsed = JSON.parse(clean); } catch(e) { parsed = { error: 'JSON parse failed', raw: raw }; }
return [{ json: { output: JSON.stringify(parsed), ...parsed } }];

